    (m_0_3 - 3 * m_2_1) * (m_0_3 + m_2_1) * ((m_0_3 + m_2_1)^2 - 3 * (m_1_2 + m_3_0)^2),
    (m_2_0 - m_0_2) * ((m_3_0 + m_1_2)^2 - (m_2_1 + m_0_3)^2) +
    4 * m_1_1 * (m_3_0 + m_1_2) * (m_2_1 + m_0_3),
    (3 * m_2_1 - m_0_3) * (m_3_0 + m_1_2) * ((m_3_0 + m_1_2)^2 - 3 * (m_2_1 + m_0_3)^2) -
    (m_3_0 - 3 * m_1_2) * (m_2_1 + m_0_3) * (3 * (m_3_0 + m_1_2)^2 - (m_2_1 + m_0_3)^2),
    m_1_1 * ((m_3_0 + m_1_2)^2 - (m_0_3 + m_2_1)^2) -
    (m_2_0 - m_0_2) * (m_3_0 + m_1_2) * (m_0_3 + m_2_1),
]

rff_flusser = RationalFunctionField(flusser_gens)
if fields_equal(rff_flusser, rff, 0.999)
    println("Simplified generators generate the same field as J. Flusser's list")
else
    println("Simplified generators DO NOT generate the same field as J. Flusser's list")
end
